const { contextBridge, ipcRenderer } = require('electron');
contextBridge.exposeInMainWorld('dinghyNative', {
  openConfig: () => ipcRenderer.invoke('config:open'),
  saveConfig: (content, opts) => ipcRenderer.invoke('config:save', content, opts || {}),
  grabFrame: (rtspUrl) => ipcRenderer.invoke('frame:grab', rtspUrl),
  onMenu: (cb) => ipcRenderer.on('menu', (_e, action) => cb(action))
});

ipcMain.handle('frame:grab', (_e, url) => new Promise(resolve => {
  const args = ['-rtsp_transport','tcp','-i',url,'-frames:v','1','-f','image2pipe','-vcodec','mjpeg','-'];
  const ff = spawn('ffmpeg', args);
  const chunks = [], errs = [];
  const timer = setTimeout(() => { ff.kill('SIGKILL'); }, 15000);
  ff.stdout.on('data', c => chunks.push(c));
  ff.stderr.on('data', c => errs.push(c));
  ff.on('error', () => { clearTimeout(timer); resolve({ error: 'ffmpeg not found — install it and ensure it is on your PATH' }); });
  ff.on('close', code => {
    clearTimeout(timer);
    if (code === 0 && chunks.length) resolve({ dataUrl: 'data:image/jpeg;base64,' + Buffer.concat(chunks).toString('base64') });
    else resolve({ error: sanitize(Buffer.concat(errs).toString().slice(-300)) });
  });
}));
